import { useTranslation } from "react-i18next";
import { Plus, Trash2 } from "lucide-react";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Button } from "@/components/ui/button";
import { Ingredient, COMMON_UNITS } from "./RecipeTypes";

interface RecipeIngredientsStepProps {
  ingredients: Ingredient[];
  onChange: (ingredients: Ingredient[]) => void;
}

const RecipeIngredientsStep = ({ ingredients, onChange }: RecipeIngredientsStepProps) => {
  const { t } = useTranslation();

  const addIngredient = () => {
    onChange([...ingredients, { name: "", amount: "", unit: "" }]);
  };

  const updateIngredient = (index: number, field: keyof Ingredient, value: string) => {
    const updated = [...ingredients];
    updated[index] = { ...updated[index], [field]: value };
    onChange(updated);
  };

  const removeIngredient = (index: number) => {
    onChange(ingredients.filter((_, i) => i !== index));
  };

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between">
        <Label className="text-base font-medium">{t("recipe.ingredients", "配料")} *</Label>
        <span className="text-sm text-muted-foreground">
          {ingredients.filter(i => i.name).length} {t("recipe.items", "项")}
        </span>
      </div>

      <div className="space-y-3">
        {ingredients.map((ingredient, index) => (
          <div key={index} className="space-y-1.5">
            <div className="flex items-center gap-2">
              <div className="flex-1">
                <Input
                  value={ingredient.name}
                  onChange={(e) => updateIngredient(index, "name", e.target.value)}
                  placeholder={t("recipe.ingredientName", "配料名称")}
                />
              </div>
              <div className="w-20">
                <Input
                  value={ingredient.amount}
                  onChange={(e) => updateIngredient(index, "amount", e.target.value)}
                  placeholder={t("recipe.amount", "量")}
                />
              </div>
              <div className="w-20">
                <Input
                  value={ingredient.unit}
                  onChange={(e) => updateIngredient(index, "unit", e.target.value)}
                  placeholder={t("recipe.unit", "单位")}
                  list="common-units"
                />
                <datalist id="common-units">
                  {COMMON_UNITS.map((unit) => (
                    <option key={unit} value={unit} />
                  ))}
                </datalist>
              </div>
              <Button
                type="button"
                variant="ghost"
                size="icon"
                onClick={() => removeIngredient(index)}
                disabled={ingredients.length === 1}
                className="shrink-0"
              >
                <Trash2 className="h-4 w-4 text-destructive" />
              </Button>
            </div>
          </div>
        ))}
      </div>

      <Button
        type="button"
        variant="outline"
        onClick={addIngredient}
        className="w-full"
      >
        <Plus className="h-4 w-4 mr-2" />
        {t("recipe.addIngredient", "添加配料")}
      </Button>

      {/* Common units hint */}
      <p className="text-xs text-muted-foreground">
        {t("recipe.unitsHint", "常用单位：g, kg, ml, L, 勺, 杯, 个, 片, 适量")}
      </p>
    </div>
  );
};

export default RecipeIngredientsStep;
